import{_ as a,o as i,c as e,a2 as d}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"ARTI AI Native Adoption","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/ai-native.md","filePath":"projects/arti/ai-native.md"}'),l={name:"projects/arti/ai-native.md"};function o(r,t,n,s,c,h){return i(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="arti-ai-native-adoption" tabindex="-1">ARTI AI Native Adoption <a class="header-anchor" href="#arti-ai-native-adoption" aria-label="Permalink to &quot;ARTI AI Native Adoption&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p>本文件记录 ARTI 如何采用组织级 AI Native 实践，以及项目特有的例外。</p><h2 id="当前成熟度" tabindex="-1">当前成熟度 <a class="header-anchor" href="#当前成熟度" aria-label="Permalink to &quot;当前成熟度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>代码附近的 Agent 指令</td><td>部分采用</td><td>四个仓库的规则文件不一致</td></tr><tr><td>RFC 驱动的重要决策</td><td>已采用</td><td>各仓库已有 RFC，但跨仓状态维护不统一</td></tr><tr><td>确定性验证</td><td>部分采用</td><td>有测试和契约校验，跨仓漂移检查仍不足</td></tr><tr><td>高风险动作人工批准</td><td>已采用</td><td>Push、部署和生产操作默认需明确授权</td></tr><tr><td>Skill 真源与 Bridge</td><td>未建立</td><td>尚未形成项目级 <code>skills/</code> 真源</td></tr><tr><td>组织记忆</td><td>建设中</td><td>Handbook 开始承担项目级索引和稳定契约</td></tr></tbody></table><h2 id="已采用实践" tabindex="-1">已采用实践 <a class="header-anchor" href="#已采用实践" aria-label="Permalink to &quot;已采用实践&quot;">​</a></h2><ul><li>组织、项目、仓库三级上下文</li><li>仓库本地规则贴近代码维护</li><li>非琐碎架构改动使用 RFC</li><li>高影响远程操作需要人类明确批准</li><li>测试和运行结果作为完成证据</li><li>共享数据库 migration 采用 append-only</li><li>失败、跳过和未验证项需要显式暴露</li></ul><h2 id="近期建设顺序" tabindex="-1">近期建设顺序 <a class="header-anchor" href="#近期建设顺序" aria-label="Permalink to &quot;近期建设顺序&quot;">​</a></h2><ol><li>为 <code>ARTI_backend</code> 和 <code>ARTI-CLI</code> 补齐平台无关的 <code>AGENTS.md</code>。</li><li>为 <code>report_tasks</code>、通知、Credits 和共享枚举增加跨仓漂移检查。</li><li>建立项目级 Skill 候选清单，再决定是否创建 <code>skills/</code> 真源。</li><li>把跨仓 RFC 的关系做成可检查索引。</li><li>登记 Agent 可执行的远程操作及其批准级别。</li></ol><h2 id="项目例外" tabindex="-1">项目例外 <a class="header-anchor" href="#项目例外" aria-label="Permalink to &quot;项目例外&quot;">​</a></h2><p>ARTI 涉及金融数据和用户资产相关逻辑。错误内容可能比缺失内容更有害，因此：</p><ul><li>数据覆盖不足时不得静默返回相似内容</li><li>资金、积分和结算相关变更需要服务端权威校验</li><li>不可逆的生产操作必须保留人工批准</li></ul><p>具体实现规则以对应仓库文档为准。</p><h2 id="可沉淀的内部案例" tabindex="-1">可沉淀的内部案例 <a class="header-anchor" href="#可沉淀的内部案例" aria-label="Permalink to &quot;可沉淀的内部案例&quot;">​</a></h2><ul><li>共享 <code>settle_market</code> RPC 被单侧旧版本覆盖，导致通知逻辑回归</li><li>客户端扣费形成“假门”，迁移为服务端权威</li><li>跨域双 Session 导致认证刷新冲突，改为同源与单一存储</li><li>Worker 旧路径长期存在于文档，排障时必须先确认真实生产入口</li></ul>',15)])])}const _=a(l,[["render",o]]);export{u as __pageData,_ as default};
